<?php require_once 'db.php'; require_once 'mailer.php'; verify_csrf(); $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $email=filter_input(INPUT_POST,'email',FILTER_VALIDATE_EMAIL); $st=pdo()->prepare('SELECT * FROM users WHERE email=?'); $st->execute([$email]); if($usr=$st->fetch()){ $token=bin2hex(random_bytes(32)); $otp=(string)random_int(100000,999999); pdo()->prepare('INSERT INTO password_resets(user_id,token,otp,expires_at) VALUES(?,?,?,DATE_ADD(NOW(),INTERVAL 30 MINUTE))')->execute([$usr['id'],$token,$otp]); $link=BASE_URL.'/reset_password.php?token='.$token; [$sub,$body]=email_template('forgot',['name'=>$usr['name'],'link'=>$link,'otp'=>$otp]); send_library_mail($usr['id'],$usr['email'],$sub,$body); } $msg='If this email exists, a reset link and OTP were sent.'; } app_header('Forgot Password'); ?><section class="auth card"><h1>Forgot Password</h1><p class="ok"><?=e($msg)?></p><form method="post"><?=csrf_field()?><input name="email" type="email" placeholder="Registered email" required><button class="btn">Send Reset Link</button></form></section><?php app_footer(); ?>
